1	//! Unit G — Message Derivation Checks (clean-room reimplementation).
2	//!
3	//! For each protocol rule, the prover decides whether every variable of the rule
4	//! is derivable by the intruder from the rule's premises. Variables that are not
5	//! derivable are reported under the wellformedness topic `Message Derivation
6	//! Checks`. The derivability decision is the prover's solver and is NOT
7	//! reimplemented here: it is supplied by the caller through [`DerivabilitySolver`].
8	//!
9	//! This crate owns four things, all characterized purely by black-box observation
10	//! of the reference tool (see workspace/BEHAVIOR.md and QUERIES.log):
11	//!   1. probe construction — which rules and which variables are handed to the
12	//!      solver, computed on the macro/let-EXPANDED rule (rule filtering, macro and
13	//!      let expansion, candidate-variable enumeration);
14	//!   2. the decision logic around solver outcomes (deactivation, timeouts,
15	//!      derivable/not-derivable);
16	//!   3. byte-exact report text and variable ordering;
17	//!   4. the batched solver interface: one saturation question per rule, carrying
18	//!      all of that rule's candidate variables.
19	
20	
21	use std::collections::HashMap;
22	use std::collections::{BTreeSet, HashSet};
23	
24	use tamarin_parser::ast::{Fact, Macro, Rule, RuleAttr, SortHint, Term, Theory, TheoryItem, VarSpec};
25	
26	/// A single wellformedness finding: a topic and its message body. Mirrors the
27	/// `WfError` surface of the wellformedness unit so findings compose into the
28	/// shared report model. For this topic the `message` is the COMPLETE block,
29	/// heading included (see [`message_derivation_checks`]).
30	#[derive(Debug, Clone, PartialEq, Eq)]
31	pub struct WfError {
32	    pub topic: String,
33	    pub message: String,
34	}
35	
36	impl WfError {
37	    pub fn new(topic: impl Into<String>, message: impl Into<String>) -> Self {
38	        WfError { topic: topic.into(), message: message.into() }
39	    }
40	}
41	
42	/// A flat report, in the order findings are rendered.
43	pub type WfReport = Vec<WfError>;
44	
45	/// The exact topic string the reference tool prints for this check.
46	pub const DERIVATION_TOPIC: &str = "Message Derivation Checks";
47	
48	/// The exact introductory paragraph the reference tool prints once, before the
49	/// per-rule blocks. Two leading spaces; no trailing whitespace.
50	pub const DERIVATION_INTRO: &str =
51	    "  The variables of the following rule(s) are not derivable from their premises, you may be performing unintended pattern matching.";
52	
53	// --------------------------------------------------------------------------
54	// Caller-supplied decision callback
55	// --------------------------------------------------------------------------
56	
57	/// The solver's verdict for one candidate variable.
58	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
59	pub enum Derivability {
60	    /// The intruder can derive the variable from the premises.
61	    Derivable,
62	    /// The intruder cannot derive the variable — it will be reported.
63	    NotDerivable,
64	    /// The derivation search exceeded the timeout budget without deciding.
65	    TimedOut,
66	}
67	
68	/// A batched derivability question: given one rule and ALL of its candidate
69	/// variables, decide each. The consuming solver saturates the rule's message
70	/// deduction once and answers every variable from that single saturation, so the
71	/// batched shape avoids the wasteful re-saturation a per-variable interface would
72	/// force. `variables` is the full candidate list for the rule; the returned
73	/// vector carries one verdict per entry, in the same order.
74	pub struct RuleProbe<'a> {
75	    pub rule_name: &'a str,
76	    pub rule: &'a Rule,
77	    pub premises: &'a [Fact],
78	    pub variables: &'a [VarSpec],
79	    pub timeout_secs: u64,
80	}
81	
82	/// The batched decision callback this crate is parameterized over. In production
83	/// it wraps the prover's message-deduction solver (one saturation per rule); in
84	/// tests it is stubbed. A per-variable callback can be adapted to it via
85	/// [`PerVariable`].
86	pub trait DerivabilitySolver {
87	    /// Decide derivability for every variable in `probe.variables`, returning one
88	    /// verdict per variable in the same order. Implementations must return a
89	    /// vector of length `probe.variables.len()`.
90	    fn check_rule(&self, probe: &RuleProbe) -> Vec<Derivability>;
91	}
92	
93	/// One derivability question for a single variable. This is the payload of the
94	/// thin per-variable adapter [`PerVariable`]; the full `rule` is provided so a
95	/// solver that needs more context than the premise facts can use it.
96	pub struct DerivProbe<'a> {
97	    pub rule_name: &'a str,
98	    pub rule: &'a Rule,
99	    pub variable: &'a VarSpec,
100	    pub premises: &'a [Fact],
101	    pub timeout_secs: u64,
102	}
103	
104	/// A per-variable decision callback. Kept as a convenience for callers whose
105	/// solver answers one variable at a time; wrap it in [`PerVariable`] to obtain a
106	/// [`DerivabilitySolver`]. A production solver should implement
107	/// [`DerivabilitySolver`] directly to saturate each rule only once.
108	pub trait PerVariableSolver {
109	    fn check(&self, probe: &DerivProbe) -> Derivability;
110	}
111	
112	/// Thin adapter turning a [`PerVariableSolver`] into a batched
113	/// [`DerivabilitySolver`] by calling it once per variable. Convenient but does
114	/// not share saturation across a rule's variables.
115	pub struct PerVariable<S>(pub S);
116	
117	impl<S: PerVariableSolver> DerivabilitySolver for PerVariable<S> {
118	    fn check_rule(&self, probe: &RuleProbe) -> Vec<Derivability> {
119	        probe
120	            .variables
121	            .iter()
122	            .map(|v| {
123	                self.0.check(&DerivProbe {
124	                    rule_name: probe.rule_name,
125	                    rule: probe.rule,
126	                    variable: v,
127	                    premises: probe.premises,
128	                    timeout_secs: probe.timeout_secs,
129	                })
130	            })
131	            .collect()
132	    }
133	}
134	
135	/// How a per-rule timeout is treated. See the residual note in BEHAVIOR.md §7:
136	/// a real per-rule timeout was not observable, so the policy is explicit here.
137	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
138	pub enum TimeoutPolicy {
139	    /// Suppress the whole rule's warning when any of its variables times out
140	    /// (fail-open; the chosen default, consistent with `timeout=0` suppressing
141	    /// all output).
142	    SuppressRule,
143	    /// Treat a timed-out variable like `Derivable` (skip only that variable) and
144	    /// still report the variables that were definitively not derivable.
145	    SkipVariable,
146	}
147	
148	impl Default for TimeoutPolicy {
149	    fn default() -> Self {
150	        TimeoutPolicy::SuppressRule
151	    }
152	}
153	
154	// --------------------------------------------------------------------------
155	// Entry points
156	// --------------------------------------------------------------------------
157	
158	/// Run the message-derivation check over a theory with the default timeout
159	/// policy. `timeout_secs` mirrors `--derivcheck-timeout`: `0` deactivates the
160	/// check and returns an empty report without consulting the solver.
161	///
162	/// The returned report is either empty (no failing rule) or a single [`WfError`]
163	/// whose `message` is the complete topic block — the underlined
164	/// `Message Derivation Checks` heading, the intro paragraph, and one block per
165	/// failing rule — byte-exact as the reference prints it. The consuming report
166	/// renderer adds no per-topic heading of its own, so the heading lives here.
167	pub fn message_derivation_checks<S: DerivabilitySolver>(
168	    thy: &Theory,
169	    solver: &S,
170	    timeout_secs: u64,
171	) -> WfReport {
172	    message_derivation_checks_with(thy, solver, timeout_secs, TimeoutPolicy::default())
173	}
174	
175	/// As [`message_derivation_checks`], with an explicit timeout policy.
176	pub fn message_derivation_checks_with<S: DerivabilitySolver>(
177	    thy: &Theory,
178	    solver: &S,
179	    timeout_secs: u64,
180	    timeout_policy: TimeoutPolicy,
181	) -> WfReport {
182	    // `--derivcheck-timeout=0` deactivates the check entirely.
183	    if timeout_secs == 0 {
184	        return Vec::new();
185	    }
186	
187	    let macros = macro_table(thy);
188	
189	    // Per-rule findings, kept in theory (source) order.
190	    let mut blocks: Vec<(String, Vec<VarSpec>)> = Vec::new();
191	
192	    for item in &thy.items {
193	        let rule = match item {
194	            TheoryItem::Rule(rule) => rule,
195	            _ => continue, // only protocol rules; intruder rules are out of scope
196	        };
197	        // A rule tagged [no_derivcheck] is skipped.
198	        if rule.attributes.iter().any(|a| matches!(a, RuleAttr::NoDerivCheck)) {
199	            continue;
200	        }
201	
202	        // Derivability is decided on the macro/let-expanded rule; candidates are
203	        // that rule's free variables.
204	        let expanded = expand_rule(rule, &macros);
205	        let candidates = candidate_variables(&expanded);
206	        if candidates.is_empty() {
207	            continue;
208	        }
209	
210	        let probe = RuleProbe {
211	            rule_name: &expanded.name,
212	            rule: &expanded,
213	            premises: &expanded.premises,
214	            variables: &candidates,
215	            timeout_secs,
216	        };
217	        let verdicts = solver.check_rule(&probe);
218	
219	        let mut flagged: Vec<VarSpec> = Vec::new();
220	        let mut rule_timed_out = false;
221	        for (var, verdict) in candidates.iter().zip(verdicts.iter().copied()) {
222	            match verdict {
223	                Derivability::Derivable => {}
224	                Derivability::NotDerivable => flagged.push(var.clone()),
225	                Derivability::TimedOut => match timeout_policy {
226	                    TimeoutPolicy::SuppressRule => {
227	                        rule_timed_out = true;
228	                        break;
229	                    }
230	                    TimeoutPolicy::SkipVariable => {}
231	                },
232	            }
233	        }
234	
235	        if rule_timed_out {
236	            continue;
237	        }
238	        if !flagged.is_empty() {
239	            sort_variables(&mut flagged);
240	            blocks.push((expanded.name.clone(), flagged));
241	        }
242	    }
243	
244	    if blocks.is_empty() {
245	        return Vec::new();
246	    }
247	
248	    // The whole topic is one value: heading + intro + one block per failing rule.
249	    vec![WfError::new(DERIVATION_TOPIC, render_block(&blocks))]
250	}
251	
252	// --------------------------------------------------------------------------
253	// Macro / let expansion (derivability is decided post-expansion)
254	// --------------------------------------------------------------------------
255	
256	/// The theory's `macros:` definitions, keyed by macro name.
257	fn macro_table(thy: &Theory) -> HashMap<String, &Macro> {
258	    let mut table = HashMap::new();
259	    for item in &thy.items {
260	        if let TheoryItem::Macros(defs) = item {
261	            for m in defs {
262	                table.insert(m.name.clone(), m);
263	            }
264	        }
265	    }
266	    table
267	}
268	
269	/// A rule with macro applications and `let` bindings fully substituted into its
270	/// premise/action/conclusion terms and its `let_block` cleared. Candidate
271	/// enumeration and the solver both operate on this expanded form, matching the
272	/// reference's post-expansion decision (BEHAVIOR.md §9).
273	fn expand_rule(rule: &Rule, macros: &HashMap<String, &Macro>) -> Rule {
274	    let lets = let_substitution(rule, macros);
275	    let map_facts = |facts: &[Fact]| -> Vec<Fact> {
276	        facts
277	            .iter()
278	            .map(|f| Fact {
279	                args: f.args.iter().map(|a| expand_term(a, macros, &lets)).collect(),
280	                ..f.clone()
281	            })
282	            .collect()
283	    };
284	    Rule {
285	        premises: map_facts(&rule.premises),
286	        actions: map_facts(&rule.actions),
287	        conclusions: map_facts(&rule.conclusions),
288	        let_block: Vec::new(),
289	        ..rule.clone()
290	    }
291	}
292	
293	/// Build the substitution induced by a rule's `let` bindings. Bindings are
294	/// sequential: each value is expanded against the macros and the bindings seen so
295	/// far, so a later `let` may reference an earlier one. A `let <a, b> = <..>`
296	/// pattern binding destructures componentwise when both sides are tuples of the
297	/// same arity.
298	fn let_substitution(rule: &Rule, macros: &HashMap<String, &Macro>) -> HashMap<VarSpec, Term> {
299	    let mut lets: HashMap<VarSpec, Term> = HashMap::new();
300	    for lb in &rule.let_block {
301	        let value = expand_term(&lb.value, macros, &lets);
302	        bind_pattern(&lb.var, &value, &mut lets);
303	    }
304	    lets
305	}
306	
307	/// Insert the binding(s) that make `pattern := value` hold. A bare variable binds
308	/// directly; a tuple pattern binds componentwise against a tuple value.
309	fn bind_pattern(pattern: &Term, value: &Term, lets: &mut HashMap<VarSpec, Term>) {
310	    match (pattern, value) {
311	        (Term::Var(v), _) => {
312	            lets.insert(v.clone(), value.clone());
313	        }
314	        (Term::Pair(ps), Term::Pair(vs)) if ps.len() == vs.len() => {
315	            for (p, v) in ps.iter().zip(vs.iter()) {
316	                bind_pattern(p, v, lets);
317	            }
318	        }
319	        _ => {} // unsupported pattern shape: leave its variables unexpanded
320	    }
321	}
322	
323	/// Expand a term: apply the `let` substitution to variables and rewrite macro
324	/// applications, recursively. `lets` values are already fully expanded.
325	fn expand_term(t: &Term, macros: &HashMap<String, &Macro>, lets: &HashMap<VarSpec, Term>) -> Term {
326	    match t {
327	        Term::Var(v) => lets.get(v).cloned().unwrap_or_else(|| t.clone()),
328	        Term::App(name, args) => {
329	            let eargs: Vec<Term> = args.iter().map(|a| expand_term(a, macros, lets)).collect();
330	            if let Some(m) = macros.get(name) {
331	                if m.args.len() == eargs.len() {
332	                    let param_map: HashMap<VarSpec, Term> =
333	                        m.args.iter().cloned().zip(eargs.iter().cloned()).collect();
334	                    let body = subst_vars(&m.body, &param_map);
335	                    return expand_term(&body, macros, lets);
336	                }
337	            }
338	            Term::App(name.clone(), eargs)
339	        }
340	        Term::Pair(args) => Term::Pair(args.iter().map(|a| expand_term(a, macros, lets)).collect()),
341	        Term::AlgApp(op, a, b) => Term::AlgApp(
342	            op.clone(),
343	            Box::new(expand_term(a, macros, lets)),
344	            Box::new(expand_term(b, macros, lets)),
345	        ),
346	        Term::BinOp(op, a, b) => Term::BinOp(
347	            *op,
348	            Box::new(expand_term(a, macros, lets)),
349	            Box::new(expand_term(b, macros, lets)),
350	        ),
351	        Term::Diff(a, b) => Term::Diff(
352	            Box::new(expand_term(a, macros, lets)),
353	            Box::new(expand_term(b, macros, lets)),
354	        ),
355	        Term::PatMatch(a) => Term::PatMatch(Box::new(expand_term(a, macros, lets))),
356	        _ => t.clone(),
357	    }
358	}
359	
360	/// Substitute variables by `map` throughout a term (used to instantiate a macro
361	/// body with its actual arguments).
362	fn subst_vars(t: &Term, map: &HashMap<VarSpec, Term>) -> Term {
363	    match t {
364	        Term::Var(v) => map.get(v).cloned().unwrap_or_else(|| t.clone()),
365	        Term::App(name, args) => {
366	            Term::App(name.clone(), args.iter().map(|a| subst_vars(a, map)).collect())
367	        }
368	        Term::Pair(args) => Term::Pair(args.iter().map(|a| subst_vars(a, map)).collect()),
369	        Term::AlgApp(op, a, b) => Term::AlgApp(
370	            op.clone(),
371	            Box::new(subst_vars(a, map)),
372	            Box::new(subst_vars(b, map)),
373	        ),
374	        Term::BinOp(op, a, b) => {
375	            Term::BinOp(*op, Box::new(subst_vars(a, map)), Box::new(subst_vars(b, map)))
376	        }
377	        Term::Diff(a, b) => Term::Diff(Box::new(subst_vars(a, map)), Box::new(subst_vars(b, map))),
378	        Term::PatMatch(a) => Term::PatMatch(Box::new(subst_vars(a, map))),
379	        _ => t.clone(),
380	    }
381	}
382	
383	// --------------------------------------------------------------------------
384	// Probe construction
385	// --------------------------------------------------------------------------
386	
387	/// The candidate variables handed to the solver for one rule: every distinct
388	/// variable occurring in the rule's premises, actions, and conclusions, in
389	/// first-occurrence order (order is irrelevant — the flagged subset is re-sorted
390	/// for display). The rule's own `let` bindings are expanded first, so a
391	/// let-bound name (the binding's left-hand side) is not itself a candidate; only
392	/// the variables of the substituted terms are. Full macro expansion additionally
393	/// requires the theory context and is applied by [`expand_rule`] before this
394	/// function is called; on an already-expanded rule this only re-applies the (now
395	/// empty) `let` substitution.
396	///
397	/// The solver decides which candidates are actually derivable, so this set is a
398	/// safe superset: public names, `Fr`-bound fresh names, and state-fact-bound
399	/// variables are all resolved to `Derivable` by the solver. A nullary function
400	/// (a declared constant) parses to `Term::App(name, [])` and contributes no
401	/// variable, so a name colliding with such a constant is never a candidate.
402	pub fn candidate_variables(rule: &Rule) -> Vec<VarSpec> {
403	    let lets = let_substitution(rule, &HashMap::new());
404	    let mut out: Vec<VarSpec> = Vec::new();
405	    let mut seen: HashSet<VarSpec> = HashSet::new();
406	    let mut push = |t: &Term| {
407	        let expanded = expand_term(t, &HashMap::new(), &lets);
408	        collect_vars(&expanded, &mut |v| {
409	            if seen.insert(v.clone()) {
410	                out.push(v.clone());
411	            }
412	        });
413	    };
414	    for f in rule.premises.iter().chain(&rule.actions).chain(&rule.conclusions) {
415	        for a in &f.args {
416	            push(a);
417	        }
418	    }
419	    out
420	}
421	
422	/// Walk a term, invoking `f` on every variable occurrence.
423	fn collect_vars(term: &Term, f: &mut impl FnMut(&VarSpec)) {
424	    match term {
425	        Term::Var(v) => f(v),
426	        Term::PubLit(_)
427	        | Term::FreshLit(_)
428	        | Term::NatLit(_)
429	        | Term::Number(_)
430	        | Term::NumberOne
431	        | Term::NatOne
432	        | Term::DhNeutral => {}
433	        Term::App(_, args) | Term::Pair(args) => {
434	            for a in args {
435	                collect_vars(a, f);
436	            }
437	        }
438	        Term::AlgApp(_, a, b) | Term::Diff(a, b) | Term::BinOp(_, a, b) => {
439	            collect_vars(a, f);
440	            collect_vars(b, f);
441	        }
442	        Term::PatMatch(a) => collect_vars(a, f),
443	    }
444	}
445	
446	// --------------------------------------------------------------------------
447	// Variable ordering and rendering
448	// --------------------------------------------------------------------------
449	
450	/// Sort flagged variables into report order and drop duplicates. The order is
451	/// ascending by `(index numerically, sort-rank, name byte-lexicographically)`.
452	pub fn sort_variables(vars: &mut Vec<VarSpec>) {
453	    vars.sort_by(var_order_key);
454	    vars.dedup();
455	}
456	
457	/// Total order used to sort reported variables (see BEHAVIOR.md §6): index is the
458	/// primary key (numeric), then sort tag (`Fresh < Msg < Nat`), then name (byte /
459	/// ASCII lexicographic, so uppercase precedes lowercase).
460	fn var_order_key(a: &VarSpec, b: &VarSpec) -> std::cmp::Ordering {
461	    a.idx
462	        .cmp(&b.idx)
463	        .then_with(|| sort_rank(a.sort).cmp(&sort_rank(b.sort)))
464	        .then_with(|| a.name.cmp(&b.name))
465	}
466	
467	/// Sort-tag rank among reportable variables: `Fresh < Msg < Nat`. Message-sort
468	/// variables carry either `Msg` or `Untagged` and rank together. `Pub` never
469	/// appears (public names are always derivable); `Node`/`Suffix` are not
470	/// expressible as message terms, so their relative rank is unobserved and placed
471	/// last.
472	fn sort_rank(sort: SortHint) -> u8 {
473	    match sort {
474	        SortHint::Fresh => 0,
475	        SortHint::Msg | SortHint::Untagged => 1,
476	        SortHint::Nat => 2,
477	        _ => 3,
478	    }
479	}
480	
481	/// Render one variable as the reference tool spells it in the warning: fresh
482	/// names carry a `~` prefix, natural-number names a `%` prefix, public names a
483	/// `$` prefix, message names none; a nonzero index is appended as `.idx`
484	/// (e.g. `x.2`).
485	pub fn render_variable(v: &VarSpec) -> String {
486	    let prefix = match v.sort {
487	        SortHint::Fresh => "~",
488	        SortHint::Nat => "%",
489	        SortHint::Pub => "$",
490	        _ => "",
491	    };
492	    if v.idx == 0 {
493	        format!("{}{}", prefix, v.name)
494	    } else {
495	        format!("{}{}.{}", prefix, v.name, v.idx)
496	    }
497	}
498	
499	/// The per-rule block body: `"Rule <name>: \nFailed to derive Variable(s): <v1>, <v2>, ..."`.
500	/// Note the trailing space after the colon on the first line.
501	fn rule_block(rule_name: &str, vars: &[VarSpec]) -> String {
502	    let list = vars.iter().map(render_variable).collect::<Vec<_>>().join(", ");
503	    format!("Rule {}: \nFailed to derive Variable(s): {}", rule_name, list)
504	}
505	
506	/// Assemble the complete topic block for the failing rules: the underlined
507	/// heading, a blank line, the intro paragraph, then one block per rule, all
508	/// separated by a single blank line. No trailing newline — the consuming report
509	/// renderer joins topic blocks with a blank line of its own.
510	fn render_block(blocks: &[(String, Vec<VarSpec>)]) -> String {
511	    let mut segments: Vec<String> = Vec::with_capacity(blocks.len() + 1);
512	    segments.push(DERIVATION_INTRO.to_string());
513	    for (name, vars) in blocks {
514	        segments.push(rule_block(name, vars));
515	    }
516	    format!("{}\n{}", underline_topic(DERIVATION_TOPIC), segments.join("\n\n"))
517	}
518	
519	// --------------------------------------------------------------------------
520	// Rendering helpers
521	// --------------------------------------------------------------------------
522	
523	/// A topic header exactly as the reference tool renders it: the title, then a
524	/// newline, then a run of `=` as long as the title, then a newline.
525	pub fn underline_topic(title: &str) -> String {
526	    let bar: String = "=".repeat(title.chars().count());
527	    format!("{}\n{}\n", title, bar)
528	}
529	
530	/// The distinct topics present in a report.
531	pub fn topics(report: &WfReport) -> BTreeSet<String> {
532	    report.iter().map(|e| e.topic.clone()).collect()
533	}
534	
535	/// Render the `Message Derivation Checks` topic block byte-exactly. The report
536	/// carries the whole topic as a single [`WfError`] whose `message` already holds
537	/// the heading, so this returns that message directly (empty string when absent).
538	pub fn render_derivation_report(report: &WfReport) -> String {
539	    report
540	        .iter()
541	        .find(|e| e.topic == DERIVATION_TOPIC)
542	        .map(|e| e.message.clone())
543	        .unwrap_or_default()
544	}
