619	    // A batched stub solver: flags exactly the variables whose name is in its set
620	    // as NotDerivable; everything else Derivable.
621	    struct FlagByName {
622	        not_derivable: HashSet<String>,
623	    }
624	    impl FlagByName {
625	        fn new(names: &[&str]) -> Self {
626	            FlagByName { not_derivable: names.iter().map(|s| s.to_string()).collect() }
627	        }
628	    }
629	    impl DerivabilitySolver for FlagByName {
630	        fn check_rule(&self, probe: &RuleProbe) -> Vec<Derivability> {
631	            probe
632	                .variables
633	                .iter()
634	                .map(|var| {
635	                    if self.not_derivable.contains(&var.name) {
636	                        Derivability::NotDerivable
637	                    } else {
638	                        Derivability::Derivable
639	                    }
640	                })
641	                .collect()
642	        }
643	    }
