646	    // thin wrapper preserves behavior.
647	    struct FlagByNamePerVar {
648	        not_derivable: HashSet<String>,
649	    }
650	    impl PerVariableSolver for FlagByNamePerVar {
651	        fn check(&self, probe: &DerivProbe) -> Derivability {
652	            if self.not_derivable.contains(&probe.variable.name) {
653	                Derivability::NotDerivable
654	            } else {
655	                Derivability::Derivable
656	            }
657	        }
658	    }
