1008	        struct Recording {
1009	            calls: RefCell<Vec<usize>>,
1010	        }
1011	        impl DerivabilitySolver for Recording {
1012	            fn check_rule(&self, probe: &RuleProbe) -> Vec<Derivability> {
1013	                self.calls.borrow_mut().push(probe.variables.len());
1014	                probe.variables.iter().map(|_| Derivability::Derivable).collect()
1015	            }
1016	        }
1017	        // One rule with three distinct candidate variables.
