1023	        );
1024	        let thy = theory(vec![TheoryItem::Rule(r)]);
1025	        let rec = Recording { calls: RefCell::new(vec![]) };
1026	        let _ = message_derivation_checks(&thy, &rec, 5);
1027	        let calls = rec.calls.borrow();
1028	        assert_eq!(calls.len(), 1, "solver must be consulted exactly once per rule");
1029	        assert_eq!(calls[0], 3, "the one call carries all three candidate variables");
