67	/// Run HS's per-variable derivability check on every rule.
68	///
69	/// `timeout_secs == 0` disables the check (returns `vec![]`).  Otherwise
70	/// each per-variable prove call is bounded by `timeout_secs` of wall-clock
71	/// time (mirrors HS's `--derivcheck-timeout`).
72	pub fn check_message_derivation(
73	    parsed: &p::Theory,
74	    maude: &MaudeHandle,
75	    timeout_secs: u32,
76	) -> Vec<WfError> {
77	    if timeout_secs == 0 { return Vec::new(); }
78	    let timeout = Duration::from_secs(timeout_secs as u64);
79	    let dbg = tamarin_utils::env_gate!("TAM_DBG_DERIV_CHECK");
80	    // TAM_DBG_DERIV_TIMING=1: emit per-rule / per-variable wall-clock
81	    // timings on stderr.  Off-path when env var is absent.
82	    let dbg_timing = tamarin_utils::env_gate!("TAM_DBG_DERIV_TIMING");
83	    let t_total_start = std::time::Instant::now();
84	
85	    // Collect the names that should NOT be treated as variables:
86	    //  * `functions: <name>/0` — user-declared 0-arity functions.
87	    //  * Builtin 0-arity constants (signing's `true`, DH's `1`, etc.).
88	    // HS-faithful: HS resolves these via `nullaryApp` at parse-time
89	    // (lib/theory/src/Theory/Text/Parser/Term.hs::nullaryApp); RS
90	    // does the same resolution at elaborate-time, but the deriv-check
91	    // walks the un-elaborated parser AST so it needs an explicit
92	    // deny-list.  See `MessageDerivationChecks.hs:39` (HS uses
93	    // `originalRules = map (applyMacroInProtoRule ...)`).
94	    let nullary_funs = collect_all_nullary_fun_names(parsed);
95	
96	    // Theory-level `macros:` declarations.  HS expands these into every
97	    // protocol rule via `applyMacroInProtoRule (theoryMacros thy)`
98	    // (MessageDerivationChecks.hs:39) BEFORE collecting free vars / building
99	    // the probe.  The caller hands us the RAW parsed theory (theory macros
100	    // un-expanded), so we must expand them here ourselves; otherwise a rule
101	    // whose body uses a macro that introduces fresh vars (e.g.
102	    // `macros: test() = ~x`) mis-collects vars and the rule is silently
103	    // skipped.
104	    let theory_macros: Vec<p::Macro> = parsed.items.iter().flat_map(|i| match i {
105	        p::TheoryItem::Macros(ms) => ms.clone(),
106	        _ => Vec::new(),
107	    }).collect();
108	
109	    let mut per_rule: Vec<(String, Vec<String>)> = Vec::new();
110	    let mut rule_count = 0usize;
111	    let mut var_count = 0usize;
112	    let mut total_synth = Duration::ZERO;
113	    let mut total_prove = Duration::ZERO;
114	    for (idx, raw_rule) in protocol_rules(parsed).enumerate() {
115	        if raw_rule.attributes.iter().any(|a| matches!(a, p::RuleAttr::NoDerivCheck)) {
116	            continue;
117	        }
118	        // HS applies theory macros before the deriv check
119	        // (MessageDerivationChecks.hs:39 -- `originalRules = map
120	        // (applyMacroInProtoRule (theoryMacros thy)) $ theoryRules thy`).
121	        // Mirror that here: first expand theory-level `macros:` into the
122	        // rule's premise/action/conclusion facts (the only parts the deriv
123	        // check inspects), THEN substitute the rule-local `let { }` block.
124	        // Theory macros are a DISTINCT AST node (`TheoryItem::Macros`) from
125	        // the rule-local let-block (`Rule.let_block`); both must be resolved
126	        // so we walk the same shape HS does.  Without macro expansion, a rule
127	        // whose body uses a fresh-introducing macro is silently skipped; and
128	        // without let-block substitution, RS flags every let-bound name
129	        // (`pkB`, `mtr`, `ci2`, ...) as non-derivable.
130	        let macro_expanded;
131	        let macro_src = if theory_macros.is_empty() {
132	            raw_rule
133	        } else {
134	            macro_expanded = apply_theory_macros_to_rule(raw_rule, &theory_macros);
135	            &macro_expanded
136	        };
137	        let expanded = crate::elaborate::apply_let_block(macro_src);
138	        let rule = &expanded;
139	        let free_vars = collect_rule_free_vars(rule, &nullary_funs);
140	        if free_vars.is_empty() { continue; }
141	        rule_count += 1;
142	
143	        // Build the probe theory ONCE per rule (it contains all the
144	        // per-variable lemmas).  The synthesised theory is small —
145	        // one rule, N lemmas, the original signature.
146	        let t_synth = std::time::Instant::now();
147	        let probe = synthesise_probe_theory(parsed, rule, idx, &free_vars);
148	        let synth_dt = t_synth.elapsed();
149	        total_synth += synth_dt;
150	        if dbg {
151	            eprintln!("[deriv] rule={} free_vars={:?}", rule.name,
152	                free_vars.iter().map(|v| &v.name).collect::<Vec<_>>());
153	            eprintln!("[deriv] probe theory items:");
154	            for it in &probe.items {
155	                match it {
156	                    p::TheoryItem::Rule(r) => eprintln!("  rule {}: prem={} act={} conc={}",
157	                        r.name, r.premises.len(), r.actions.len(), r.conclusions.len()),
158	                    p::TheoryItem::Lemma(l) => eprintln!("  lemma {} ({:?})",
159	                        l.name, l.trace_quantifier),
160	                    _ => {}
161	                }
162	            }
163	        }
164	
165	        // Try each variable's lemma.  HS's "TraceFound" status maps
166	        // to RS's `NodeStatus::Solved` for exists-trace lemmas.
167	        //
168	        // HS-faithful structure: `closeTheoryWithMaude` is called ONCE
169	        // per probe theory (HS `MessageDerivationChecks.hs:40-44`
170	        // calls `closeTheoryWithMaude` once per modified theory; then
171	        // `proveTheory` walks the N lemmas reusing the closed theory's
172	        // sources/cache — `Prover.hs:260-279`).  `prove_probe` mirrors
173	        // this: build the `ProofContext` + run `ensure_saturated()` ONCE
174	        // per probe, then iterate the per-variable lemmas reusing it.
175	        let outcome = match prove_probe(&probe, maude.clone(), idx, &free_vars, timeout, dbg_timing, &rule.name) {
176	            Some(o) => o,
177	            None => continue,
178	        };
179	        // Fold the probe's debug-only timing/count into the running totals.
180	        total_prove += outcome.prove_time;
181	        var_count += outcome.var_count;
182	        let undecidable = outcome.undecidable;
183	        if dbg_timing {
184	            eprintln!(
185	                "[deriv-timing] rule={} synth={:.3}s nvars={} total_prove={:.3}s",
186	                rule.name, synth_dt.as_secs_f64(), free_vars.len(),
187	                total_prove.as_secs_f64(),
188	            );
189	        }
190	        if !undecidable.is_empty() {
191	            per_rule.push((rule.name.clone(), undecidable));
192	        }
193	    }
194	    if dbg_timing {
195	        eprintln!(
196	            "[deriv-timing] TOTAL rules={} vars={} synth={:.3}s prove={:.3}s wall={:.3}s",
197	            rule_count, var_count,
198	            total_synth.as_secs_f64(),
199	            total_prove.as_secs_f64(),
200	            t_total_start.elapsed().as_secs_f64(),
201	        );
202	    }
203	    format_deriv_report(&per_rule)
204	}
