206	/// Expand theory-level `macros:` into a rule's premise / action / conclusion
207	/// facts and its `let { }` block — the parts the deriv check inspects.  Mirror
208	/// of HS `applyMacroInProtoRule (theoryMacros thy)`
209	/// (MessageDerivationChecks.hs:39).
210	fn apply_theory_macros_to_rule(rule: &p::Rule, macros: &[p::Macro]) -> p::Rule {
211	    let mut r = rule.clone();
212	    for f in &mut r.premises {
213	        *f = crate::macro_expand::apply_macros_fact(macros, f);
214	    }
215	    for f in &mut r.actions {
216	        *f = crate::macro_expand::apply_macros_fact(macros, f);
217	    }
218	    for f in &mut r.conclusions {
219	        *f = crate::macro_expand::apply_macros_fact(macros, f);
220	    }
221	    for b in &mut r.let_block {
222	        b.value = crate::macro_expand::apply_macros_term(macros, &b.value);
223	        b.var = crate::macro_expand::apply_macros_term(macros, &b.var);
224	    }
225	    r
226	}
