228	/// Iterate over Rule items in declaration order.  Skips IntrRule
229	/// declarations (intruder rules), Restrictions, Lemmas.
230	fn protocol_rules(thy: &p::Theory) -> impl Iterator<Item = &p::Rule> {
231	    thy.items.iter().filter_map(|it| match it {
232	        p::TheoryItem::Rule(r) => Some(r),
233	        _ => None,
234	    })
235	}
