237	/// HS-faithful counterpart to `nullaryApp` (parser-state-driven
238	/// 0-arity function-symbol lookup, `Theory/Text/Parser/Term.hs`).
239	/// Combines (a) user-declared `functions: name/0` and (b) the 0-arity
240	/// constants any enabled `builtins:` declaration brings in (signing's
241	/// `true`, DH's `1`, etc.).
242	fn collect_all_nullary_fun_names(thy: &p::Theory) -> std::collections::BTreeSet<String> {
243	    let mut out: std::collections::BTreeSet<String> = std::collections::BTreeSet::new();
244	    for it in &thy.items {
245	        match it {
246	            p::TheoryItem::Functions(decls) => {
247	                for d in decls {
248	                    if d.arg_types.is_empty() {
249	                        out.insert(d.name.clone());
250	                    }
251	                }
252	            }
253	            p::TheoryItem::Builtins(names) => {
254	                for n in names {
255	                    for c in crate::elaborate::builtin_nullary_constants(n) {
256	                        out.insert(c);
257	                    }
258	                }
259	            }
260	            _ => {}
261	        }
262	    }
263	    out
264	}
