266	/// All variables that appear anywhere in a rule's premise / action /
267	/// conclusion terms, deduped and returned sorted by HS `LVar` Ord
268	/// (idx, then sort, then name) — matching HS `frees`/`S.toList`, which
269	/// yields elements in ascending LVar Ord.  (Internally the dedup pass
270	/// collects in first-occurrence order, but the result is re-sorted before
271	/// return.)  EXCLUDING:
272	///   - `Pub`-sort vars (`$x`) — RS drops these up-front as a sound
273	///     optimization.  HS keeps them in `freeVars` (its `freesInThyRules`,
274	///     MessageDerivationChecks.hs:168-172, filters out only `LSortNode`,
275	///     not `LSortPub`) and generates a `KU($x)` lemma for each; but the
276	///     intruder knows every public name, so those lemmas are ALWAYS
277	///     TraceFound and the pub var is never reported.  (`deleteGlobals`,
278	///     MessageDerivationChecks.hs:190-191, does drop Pub vars, but only
279	///     inside the generated rule/action, not from the reported var list.)
280	///   - `Node`-sort vars (`#i`) — timepoints, not message vars.  HS's
281	///     `freesInThyRules` filters these out (the only sort it drops).
282	///   - Suffix-sorted vars whose underlying sort is Pub or Node, for the
283	///     same reason.
284	///   - Names that are actually 0-arity function calls (e.g. user-
285	///     declared `true/0`, builtin `1`).  HS-faithful: `nullaryApp`
286	///     resolves these to `App` not `Var` at parse-time.
287	fn collect_rule_free_vars(
288	    r: &p::Rule,
289	    nullary_funs: &std::collections::BTreeSet<String>,
290	) -> Vec<p::VarSpec> {
291	    let mut out: Vec<p::VarSpec> = Vec::new();
292	    // HS `frees` keys on the full LVar (name AND sort AND idx), so `~ltk`
293	    // (fresh) and `ltk` (msg) are DISTINCT free vars — both become
294	    // derivability candidates.  Key the dedup set on (name, sort, idx) too;
295	    // a (name, idx)-only key would let `~ltk` mask `ltk` and silently drop
296	    // the non-derivable msg var (Register_pk `ltk`).
297	    let mut seen: std::collections::BTreeSet<(String, u8, u64)> = std::collections::BTreeSet::new();
298	    let push = |v: &p::VarSpec, out: &mut Vec<p::VarSpec>, seen: &mut std::collections::BTreeSet<(String, u8, u64)>| {
299	        if matches!(v.sort, p::SortHint::Pub | p::SortHint::Node) {
300	            return;
301	        }
302	        if matches!(v.sort, p::SortHint::Suffix(p::SuffixSort::Pub)
303	            | p::SortHint::Suffix(p::SuffixSort::Node))
304	        {
305	            return;
306	        }
307	        if nullary_funs.contains(&v.name) {
308	            return;
309	        }
310	        let key = (v.name.clone(), sort_ord(&v.sort), v.idx);
311	        if seen.insert(key) {
312	            out.push(v.clone());
313	        }
314	    };
315	    let visit_term = |t: &p::Term, out: &mut Vec<p::VarSpec>, seen: &mut _| {
316	        let mut vs = Vec::new();
317	        collect_term_vars(t, &mut vs);
318	        for v in vs { push(&v, out, seen); }
319	    };
320	    for f in &r.premises { for a in &f.args { visit_term(a, &mut out, &mut seen); } }
321	    for f in &r.actions { for a in &f.args { visit_term(a, &mut out, &mut seen); } }
322	    for f in &r.conclusions { for a in &f.args { visit_term(a, &mut out, &mut seen); } }
323	    // HS-faithful: sort by (idx, sort, name) to match HS's `LVar Ord`
324	    // (LTerm.hs:522-524: `compare x3 y3 <> compare x2 y2 <> compare x1 y1`
325	    //  where x3=idx, x2=sort, x1=name).  HS uses `frees . L.get oprRuleE` →
326	    // `S.toList` which returns elements in ascending LVar Ord.
327	    out.sort_by(|a, b| {
328	        a.idx.cmp(&b.idx)
329	            .then_with(|| sort_ord(&a.sort).cmp(&sort_ord(&b.sort)))
330	            .then_with(|| a.name.cmp(&b.name))
331	    });
332	    out
333	}
334	
335	/// HS LSort derived-Ord: Pub=0, Fresh=1, Msg=2, Node=3, Nat=4 (untagged →
336	/// Msg).  Used both for LVar ordering and as the sort component of the
337	/// free-var identity key (a (name, idx)-only key would conflate `~ltk` and
338	/// `ltk`).
339	fn sort_ord(s: &p::SortHint) -> u8 {
340	    match s {
341	        p::SortHint::Pub | p::SortHint::Suffix(p::SuffixSort::Pub) => 0,
342	        p::SortHint::Fresh | p::SortHint::Suffix(p::SuffixSort::Fresh) => 1,
343	        p::SortHint::Msg | p::SortHint::Suffix(p::SuffixSort::Msg)
344	            | p::SortHint::Untagged => 2,
345	        p::SortHint::Node | p::SortHint::Suffix(p::SuffixSort::Node) => 3,
346	        p::SortHint::Nat | p::SortHint::Suffix(p::SuffixSort::Nat) => 4,
347	    }
348	}
349	
350	/// HS `lvarToLnterm`: retype an LSortNat var to LSortFresh; otherwise keep
351	/// the var's sort unchanged (MessageDerivationChecks.hs:216-218).
352	fn nat_to_fresh_var(v: &p::VarSpec) -> p::VarSpec {
353	    let mut nv = v.clone();
354	    if matches!(v.sort, p::SortHint::Nat | p::SortHint::Suffix(p::SuffixSort::Nat)) {
355	        nv.sort = p::SortHint::Fresh;
356	    }
357	    nv
358	}
