360	/// Rename a premise term's variables for the probe: a free var (matched by
361	/// (name, sort, idx)) becomes its `dvar<k>` probe var; any other var is
362	/// retyped nat→fresh (HS `natToFreshVars`).  Keeps `Out(...)` referencing the
363	/// same probe vars as the `Fr(...)` premises.
364	// (name,sort,idx)->probe-var rename map; keyed lookup only;
365	// std kept (byte-inert) — iteration order never reaches output.
366	#[allow(clippy::disallowed_types)]
367	fn rename_term_to_probe(
368	    t: &p::Term,
369	    map: &std::collections::HashMap<(String, u8, u64), p::VarSpec>,
370	) -> p::Term {
371	    match t {
372	        p::Term::Var(v) => {
373	            let key = (v.name.clone(), sort_ord(&v.sort), v.idx);
374	            match map.get(&key) {
375	                Some(pv) => p::Term::Var(pv.clone()),
376	                None => p::Term::Var(nat_to_fresh_var(v)),
377	            }
378	        }
379	        p::Term::App(name, args) => p::Term::App(
380	            name.clone(),
381	            args.iter().map(|a| rename_term_to_probe(a, map)).collect(),
382	        ),
383	        p::Term::Pair(args) => p::Term::Pair(
384	            args.iter().map(|a| rename_term_to_probe(a, map)).collect(),
385	        ),
386	        p::Term::BinOp(op, l, r) => p::Term::BinOp(
387	            *op,
388	            Box::new(rename_term_to_probe(l, map)),
389	            Box::new(rename_term_to_probe(r, map)),
390	        ),
391	        p::Term::AlgApp(name, l, r) => p::Term::AlgApp(
392	            name.clone(),
393	            Box::new(rename_term_to_probe(l, map)),
394	            Box::new(rename_term_to_probe(r, map)),
395	        ),
396	        _ => t.clone(),
397	    }
398	}
