400	fn collect_term_vars(t: &p::Term, out: &mut Vec<p::VarSpec>) {
401	    match t {
402	        p::Term::Var(v) => out.push(v.clone()),
403	        p::Term::App(_, args) | p::Term::Pair(args) => {
404	            for a in args { collect_term_vars(a, out); }
405	        }
406	        p::Term::BinOp(_, l, rt) => { collect_term_vars(l, out); collect_term_vars(rt, out); }
407	        p::Term::AlgApp(_, l, rt) => { collect_term_vars(l, out); collect_term_vars(rt, out); }
408	        _ => {}
409	    }
410	}
