412	/// Build the per-rule probe theory:
413	///
414	/// ```text
415	///   theory Probe_<idx>
416	///     <copy of original signature: builtins, functions, equations, macros>
417	///
418	///     rule Probe_<idx>:
419	///       [ Fr(~v) for each free Fresh-sort var ]
420	///       --[ Generated_<idx>(v1, v2, ...) ]->
421	///       [ Out(t) for each premise term in R ]
422	///
423	///     lemma deriv_check_<idx>_<v>: exists-trace
424	///       "Ex v1 v2 ... #t0 #t1. Generated_<idx>(...) @ #t0 & KU(v) @ #t1"
425	/// ```
426	///
427	/// ...one per free var...  (two distinct timepoints; the knowledge
428	/// predicate is `KU`, not `K` — consistent with the module header
429	/// and the inline comment in the body.)
430	// (name,sort,idx)->probe-var rename map; keyed lookup only;
431	// std kept (byte-inert) — iteration order never reaches output.
432	#[allow(clippy::disallowed_types)]
433	fn synthesise_probe_theory(
434	    src: &p::Theory,
435	    rule: &p::Rule,
436	    idx: usize,
437	    free_vars: &[p::VarSpec],
438	) -> p::Theory {
439	    let mut probe = p::Theory {
440	        is_diff: false,
441	        name: format!("Probe_{}", idx),
442	        configuration: None,
443	        items: Vec::new(),
444	    };
445	    // Carry over the signature items VERBATIM.  Drops rules/lemmas/restrictions.
446	    //
447	    // HS keeps the maude signature PRIVATE for the deriv-check probe.  Two HS
448	    // operations look like they make symbols public, but neither affects the
449	    // verdict:
450	    //   * `makeFunsPublic` (MessageDerivationChecks.hs:43,100-101) is just
451	    //     `L.set thySignature (toSignaturePure sig)` — it sets the OPEN theory's
452	    //     *pure* signature, which `closeTheoryWithMaude sig ...`
453	    //     (MessageDerivationChecks.hs:41, Prover.hs:171-178) immediately
454	    //     OVERWRITES with the ORIGINAL `SignatureWithMaude sig` (the 5th field
455	    //     of the `Theory` record).  Intruder-rule generation runs off that
456	    //     original maude signature (`closeRuleCache ... sig ...`, Rule.hs:144),
457	    //     so destructor/constructor rules see the symbols as Private exactly as
458	    //     in the real theory.  `makeFunsPublic` is a misnomer that touches only
459	    //     pretty/storage state, never the verdict.
460	    //   * `replacePrivate` (MessageDerivationChecks.hs:46,94-98) rewrites a
461	    //     private NoEq head on the Out terms to a Public-headed variant of the
462	    //     SAME name/arity.  That variant is never inserted into `stFunSyms`/
463	    //     `stRules`, so it gets no construction rule (constructionRules iterates
464	    //     `stFunSyms`, IntruderRules.hs:217-219) and no destruction rule (stRules
465	    //     is keyed on the original private symbol; the variant matches nothing).
466	    //     The intruder can coerce the whole opaque application KD→KU but cannot
467	    //     peel a sub-variable out of it — behaviorally identical to leaving the
468	    //     private application in place.  In RS, privacy is resolved by NAME at
469	    //     elaborate time (elaborate.rs `set_user_funs_for_theory`), so there is
470	    //     no per-occurrence public variant; emulating `replacePrivate` would
471	    //     resolve to the real public signature symbol and re-introduce the
472	    //     divergence.  So we mirror HS by doing NEITHER: keep privacy as-is.
473	    //
474	    // The Rust intruder-rule generation (intruder_rules.rs:164 destructor-skip,
475	    // :648 Public-only `construction_rules` filter, `private_constructor_rules`)
476	    // already matches IntruderRules.hs:149/219 once the privacy flags survive.
477	    for it in &src.items {
478	        match it {
479	            p::TheoryItem::Functions(_)
480	            | p::TheoryItem::Builtins(_)
481	            | p::TheoryItem::Equations { .. }
482	            | p::TheoryItem::Macros(_) => {
483	                probe.items.push(it.clone());
484	            }
485	            _ => {}
486	        }
487	    }
488	    // HS `generateRule` (MessageDerivationChecks.hs:181) keeps each free
489	    // var's ORIGINAL sort: premises = `freesToFresh . deleteGlobals` and
490	    // `freesToFresh = map (freshFact . lvarToLnterm)` where `lvarToLnterm`
491	    // only retypes LSortNat → LSortFresh (everything else stays as-is).
492	    // So `~ltk` (fresh) and `ltk` (msg) become Fr(~ltk) and Fr(ltk) — two
493	    // DISTINCT premises; Out(~ltk) makes ~ltk derivable while KU(ltk) is
494	    // not.  Keying the rename map on (name, sort, idx) — not (name, idx)
495	    // alone — is required so same-named vars of different sorts (e.g.
496	    // Register_pk's `~ltk` vs `ltk`) stay distinct.
497	    // Each free var gets a UNIQUE probe name (`dvar<k>`) keeping its sort
498	    // (nat→fresh).  HS distinguishes same-named/different-sort vars (`~ltk`
499	    // vs `ltk`) via sort-aware LVar identity in de Bruijn conversion; RS's
500	    // `formula_to_guarded` keys binders by NAME (not the full sort-aware
501	    // LVar identity), so two `Ex ltk ltk` binders would be ambiguous and
502	    // mis-resolve `KU(~ltk)`.  The unique `dvar<k>` naming is the mechanism
503	    // that recovers HS's sort-disambiguation, with NO effect on derivability
504	    // (variable names are immaterial to the intruder); the original var name
505	    // is restored for the WfError report via `show_lvar` (prove_probe uses
506	    // `free_vars`).
507	    let probe_vars: Vec<p::VarSpec> = free_vars.iter().enumerate()
508	        .map(|(k, v)| {
509	            let mut nv = nat_to_fresh_var(v);
510	            nv.name = format!("dvar{}", k);
511	            nv.idx = 0;
512	            nv
513	        })
514	        .collect();
515	    // Sort-aware (name, sort, idx) → probe-var map for renaming premise terms
516	    // (so `Out(~ltk)` references the same `dvar<k>` as `Fr(dvar<k>)`).
517	    let rename: std::collections::HashMap<(String, u8, u64), p::VarSpec> =
518	        free_vars.iter().enumerate()
519	            .map(|(k, v)| ((v.name.clone(), sort_ord(&v.sort), v.idx), probe_vars[k].clone()))
520	            .collect();
521	    let fresh_premises: Vec<p::Fact> = probe_vars.iter()
522	        .map(|v| p::Fact {
523	            persistent: false,
524	            name: "Fr".into(),
525	            args: vec![p::Term::Var(v.clone())],
526	            annotations: Vec::new(),
527	        })
528	        .collect();
529	    // HS `generateAction vars idx = protoFact Persistent ("Generated_" ++
530	    // show idx) (...)` (MessageDerivationChecks.hs:185) — the Generated fact
531	    // is Persistent.  For a ProtoFact the multiplicity rides in the tag, and
532	    // both the probe rule's action and the lemma's action atom are built from
533	    // this same `action`, so they stay mutually consistent.  Match HS exactly.
534	    let action = p::Fact {
535	        persistent: true,
536	        name: format!("Generated_{}", idx),
537	        args: probe_vars.iter().map(|v| p::Term::Var(v.clone())).collect(),
538	        annotations: Vec::new(),
539	    };
540	    // premisesToOut = map (outFact . natToFreshVars) . concatMap factTerms:
541	    // Out each premise term, with free-var occurrences renamed to their
542	    // `dvar<k>` probe var (and nat-sort non-free vars retyped to fresh).
543	    let out_concs: Vec<p::Fact> = rule.premises.iter()
544	        .flat_map(|f| f.args.iter().cloned())
545	        .map(|t| p::Fact {
546	            persistent: false,
547	            name: "Out".into(),
548	            args: vec![rename_term_to_probe(&t, &rename)],
549	            annotations: Vec::new(),
550	        })
551	        .collect();
552	    let probe_rule = p::Rule {
553	        name: format!("Probe_{}", idx),
554	        modulo: None,
555	        attributes: Vec::new(),
556	        let_block: Vec::new(),
557	        premises: fresh_premises,
558	        actions: vec![action.clone()],
559	        conclusions: out_concs,
560	        embedded_restrictions: Vec::new(),
561	        variants: Vec::new(),
562	        left_right: None,
563	    };
564	    probe.items.push(p::TheoryItem::Rule(probe_rule));
565	
566	    // Build one lemma per free var.  HS's `landFormula` gives each
567	    // conjoined fact its OWN timepoint (MessageDerivationChecks.hs:202-203):
568	    //   `Generated_<idx>(...) @ #t0  ∧  KU(v) @ #t1`
569	    // Two DIFFERENT timepoints — asking "is there ever a time the
570	    // intruder knows v AND a (possibly different) time Generated fires?"
571	    // not "are these simultaneous".  The intruder-knowledge predicate
572	    // is `KU` (HS's `lntermToKUFact = kuFact`), not `K`.
573	    let action_atom = |action: p::Fact, t: p::Term| -> p::Formula {
574	        p::Formula::Atom(p::Atom::Action(action, t))
575	    };
576	    for (k, _v) in free_vars.iter().enumerate() {
577	        // Lemma named by free-var INDEX (not name) so same-named vars don't
578	        // collide; prove_probe re-derives the same name from the index.
579	        let lemma_name = format!("deriv_check_{}_{}", idx, k);
580	        let v_renamed = probe_vars[k].clone();
581	        let t0 = p::VarSpec { name: "t0".into(), idx: 0, sort: p::SortHint::Node, typ: None };
582	        let t1 = p::VarSpec { name: "t1".into(), idx: 0, sort: p::SortHint::Node, typ: None };
583	        let gen_at = action_atom(action.clone(), p::Term::Var(t0.clone()));
584	        let ku_fact = p::Fact {
585	            // KU is Persistent per factTagMultiplicity (Model/Fact.hs:356);
586	            // keep the "for special names, persistent == tag multiplicity"
587	            // invariant so GFact equality with parsed KU facts is faithful.
588	            persistent: true,
589	            name: "KU".into(),
590	            args: vec![p::Term::Var(v_renamed)],
591	            annotations: Vec::new(),
592	        };
593	        let ku_at = action_atom(ku_fact, p::Term::Var(t1.clone()));
594	        let conj = p::Formula::And(Box::new(gen_at), Box::new(ku_at));
595	        // Ex t0 t1 vars... . <conj>
596	        let mut all_quant = probe_vars.clone();
597	        all_quant.push(t0);
598	        all_quant.push(t1);
599	        let body = p::Formula::Exists(all_quant, Box::new(conj));
600	        probe.items.push(p::TheoryItem::Lemma(p::Lemma {
601	            name: lemma_name,
602	            modulo: None,
603	            attributes: Vec::new(),
604	            trace_quantifier: p::TraceQuantifier::ExistsTrace,
605	            formula: body,
606	            proof: None,
607	            plaintext: String::new(),
608	        }));
609	    }
610	
611	    probe
612	}
