614	/// Result of probing a single rule: the non-derivable variable names plus
615	/// debug-only timing/count accumulators (folded into the caller's running
616	/// totals at the call site).
617	struct ProbeOutcome {
618	    /// Variable names whose lemma did NOT find a trace (= non-derivable).
619	    undecidable: Vec<String>,
620	    /// Wall-clock spent in `run_proof_search` across this probe's lemmas.
621	    prove_time: Duration,
622	    /// Number of per-variable proof attempts made for this probe.
623	    var_count: usize,
624	}
625	
626	/// HS-faithful per-probe prover.  Builds the elaborated probe theory
627	/// and a single `ProofContext` (with one `ensure_saturated` call),
628	/// then iterates the per-variable lemmas, invoking `run_proof_search`
629	/// directly on each lemma's `System` with the shared, already-saturated
630	/// context.
631	///
632	/// Mirrors HS's `closeTheoryWithMaude` (called once per modified theory
633	/// in `MessageDerivationChecks.hs:40-44`) followed by `proveTheory`'s
634	/// per-lemma walk (`Prover.hs:260-279`).  Returns `None` on elaboration
635	/// failure (caller continues to the next probe rule); otherwise returns
636	/// a `ProbeOutcome` whose `undecidable` lists the variable names whose
637	/// lemma did NOT find a trace (= non-derivable variables).
638	fn prove_probe(
639	    probe: &p::Theory,
640	    maude: MaudeHandle,
641	    idx: usize,
642	    free_vars: &[p::VarSpec],
643	    timeout: Duration,
644	    dbg_timing: bool,
645	    rule_name: &str,
646	) -> Option<ProbeOutcome> {
647	    use crate::constraint::solver::context::ProofContext;
648	    use crate::constraint::solver::search::{run_proof_search, NodeStatus};
649	    use crate::constraint::system::{formula_to_system, SourceKind};
650	    use crate::elaborate::elaborate;
651	    use crate::guarded::formula_to_guarded;
652	    use crate::theory::OpenProtoRule;
653	
654	    // Per-prove deadline gate: set TAM_PROVE_DEADLINE_MS from `timeout`
655	    // so each variable's `run_proof_search` still honours the deadline.
656	    // The RAII guard restores the prior value on EVERY exit path (including
657	    // any future early-return), so the deadline can't leak into the main
658	    // prove loop.
659	    let ms = (timeout.as_millis() as u64).max(1);
660	    let _deadline_guard = DeadlineEnvGuard::set(ms);
661	
662	    let _user_funs_guard = crate::elaborate::set_user_funs_for_theory(probe);
663	    let elaborated = match elaborate(probe) {
664	        Ok(t) => t,
665	        Err(_) => return None,
666	    };
667	    let rules: Vec<OpenProtoRule> = elaborated.rules().cloned().collect();
668	    let mut ctx = ProofContext::new_with_restrictions(maude, rules, Vec::new());
669	    ctx.is_exists_trace = true;
670	    // Probes have no `[sources]`-tagged lemmas, so no typing
671	    // assumptions — but `ensure_saturated()` still must run to compute
672	    // the source-case cache exactly as HS's `closeTheoryWithMaude`
673	    // does once per modified theory (Prover.hs:170-251).
674	    ctx.ensure_saturated();
675	
676	    let mut undecidable = Vec::new();
677	    let mut prove_time = Duration::ZERO;
678	    let mut var_count = 0usize;
679	    for (k, v) in free_vars.iter().enumerate() {
680	        // Lemma name keyed by free-var INDEX (matches synthesise_probe_theory);
681	        // the reported var name below uses the ORIGINAL `v` (sort + name).
682	        let lemma_name = format!("deriv_check_{}_{}", idx, k);
683	        let lemma = match elaborated.lookup_lemma(&lemma_name) {
684	            Some(l) => l,
685	            None => continue,
686	        };
687	        let g = match formula_to_guarded(&lemma.formula) {
688	            Ok(g) => g,
689	            Err(_) => continue,
690	        };
691	        let sys = formula_to_system(
692	            Vec::new(),
693	            SourceKind::RawSources,
694	            p::TraceQuantifier::ExistsTrace,
695	            false,
696	            &g,
697	        );
698	        let t_prove = std::time::Instant::now();
699	        let result = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
700	            run_proof_search(&ctx, sys, 1000)
701	        }));
702	        // A panic inside the prover is an INTERNAL bug, not a timeout
703	        // (timeouts return a non-Solved status, not a panic).  Log it to
704	        // stderr so it isn't silently mis-reported to the user as a
705	        // "Failed to derive Variable(s)" wellformedness result.  We still
706	        // fall through to `ok = false` (the variable is left in the report)
707	        // to preserve the existing conservative behaviour.
708	        if result.is_err() {
709	            eprintln!(
710	                "[deriv] WARNING: solver panicked while checking derivability of \
711	                 variable `{}` in rule `{}`; reporting it as non-derivable. \
712	                 This is an internal prover bug, not necessarily a theory problem.",
713	                v.name, rule_name,
714	            );
715	        }
716	        let ok = matches!(result, Ok(ref n) if matches!(n.status, NodeStatus::Solved));
717	        let prove_dt = t_prove.elapsed();
718	        prove_time += prove_dt;
719	        var_count += 1;
720	        if dbg_timing {
721	            eprintln!(
722	                "[deriv-timing] rule={} var={} prove={:.3}s ok={}",
723	                rule_name, v.name, prove_dt.as_secs_f64(), ok,
724	            );
725	        }
726	        if !ok {
727	            // HS reports `show LVar` (sortPrefix ++ body) for the
728	            // undecidable variable (MessageDerivationChecks.hs:138,156).
729	            undecidable.push(show_lvar(v));
730	        }
731	    }
732	
733	    Some(ProbeOutcome { undecidable, prove_time, var_count })
734	}
735	
736	/// HS `Show LVar`: `sortPrefix s ++ body`, where body is the name (or, if
737	/// `idx /= 0`, `name.idx`; if the name is empty, just the index).
738	fn show_lvar(v: &p::VarSpec) -> String {
739	    let prefix = match v.sort {
740	        p::SortHint::Fresh | p::SortHint::Suffix(p::SuffixSort::Fresh) => "~",
741	        p::SortHint::Pub | p::SortHint::Suffix(p::SuffixSort::Pub) => "$",
742	        p::SortHint::Node | p::SortHint::Suffix(p::SuffixSort::Node) => "#",
743	        p::SortHint::Nat | p::SortHint::Suffix(p::SuffixSort::Nat) => "%",
744	        _ => "",
745	    };
746	    let body = if v.name.is_empty() {
747	        v.idx.to_string()
748	    } else if v.idx == 0 {
749	        v.name.clone()
750	    } else {
751	        format!("{}.{}", v.name, v.idx)
752	    };
753	    format!("{}{}", prefix, body)
754	}
