756	/// RAII guard for the `TAM_PROVE_DEADLINE_MS` env var (mirrors the
757	/// thread-local `User*FunsGuard` idiom in `elaborate.rs`).  On `set` it
758	/// records the prior value and installs `ms`; on drop it restores the
759	/// prior value (or removes it if unset).  This guarantees the per-probe
760	/// deadline cannot leak into the main prove loop on any exit path.
761	struct DeadlineEnvGuard {
762	    previous: Option<String>,
763	}
764	
765	impl DeadlineEnvGuard {
766	    fn set(ms: u64) -> Self {
767	        let previous = std::env::var("TAM_PROVE_DEADLINE_MS").ok();
768	        std::env::set_var("TAM_PROVE_DEADLINE_MS", ms.to_string());
769	        DeadlineEnvGuard { previous }
770	    }
771	}
772	
773	impl Drop for DeadlineEnvGuard {
774	    fn drop(&mut self) {
775	        match self.previous.take() {
776	            Some(v) => std::env::set_var("TAM_PROVE_DEADLINE_MS", v),
777	            None => std::env::remove_var("TAM_PROVE_DEADLINE_MS"),
778	        }
779	    }
780	}
781	
782	fn format_deriv_report(per_rule: &[(String, Vec<String>)]) -> Vec<WfError> {
783	    if per_rule.is_empty() { return Vec::new(); }
784	    // HS `reportVars` (Theory/Tools/MessageDerivationChecks.hs:122-127)
785	    //   `[(underlineTopic "Message Derivation Checks",
786	    //     text $ "The variables of the following rule(s) ... pattern matching.\n\n" ++ errors)]`
787	    // The renderer in HS (`prettyWfErrorReport`) lays the topic + body
788	    // out as `<title>\n<====>\n\n  <body>\n`. The body is then indented
789	    // by 2 spaces at its first line via `nest 2`-equivalent, then the
790	    // per-rule blocks follow at col 0. See HS output bytes — the intro
791	    // line has a 2-space leading indent.
792	    let mut msg = tamarin_parser::wf::underline_topic("Message Derivation Checks");
793	    msg.push('\n');
794	    msg.push_str(
795	        "  The variables of the following rule(s) are not derivable \
796	         from their premises, you may be performing unintended pattern \
797	         matching.\n\n");
798	    // The per-rule blocks are intentionally NOT 2-space-indented: HughesPJ
799	    // `nest 2` re-indents only the first line of a `text`, leaving text that
800	    // follows a literal `\n` un-reindented, so HS's 2-space indent lands on
801	    // the intro line only and every `Rule X:` block starts at column 0.
802	    let blocks: Vec<String> = per_rule.iter()
803	        .map(|(rule_name, vars)| {
804	            format!("Rule {}: \nFailed to derive Variable(s): {}",
805	                rule_name, vars.join(", "))
806	        })
807	        .collect();
808	    msg.push_str(&blocks.join("\n\n"));
809	    vec![WfError::new("Message Derivation Checks", msg)]
810	}
