#!/usr/bin/env bash
# Extract just the "Message Derivation Checks" topic block from a full
# tamarin stdout (the WARNING /* ... */ comment). Prints nothing if absent.
# The block runs from the "Message Derivation Checks" title line until the
# next topic header (Title line immediately followed by an all-'=' underline)
# or the closing '*/' of the comment.
awk '
  BEGIN { grab=0 }
  # closing of the warning comment ends any block
  /^\*\/$/ { if (grab) exit; next }
  {
    if (!grab) {
      if ($0 == "Message Derivation Checks") { grab=1; print; next }
      next
    }
    # already grabbing: check if THIS line starts a new (different) topic.
    # A topic header is a title line whose NEXT line is all '='.
    if (prev_was_title && $0 ~ /^=+$/ && title != "Message Derivation Checks") {
      exit
    }
    print
  }
  { title=$0; if ($0 ~ /^[^ =].*[^ ]$/ && $0 !~ /^=+$/) prev_was_title=1; else prev_was_title=0 }
' "$1"

